		QueryDigest runWorkload() {
			if (selector().queryCount == 1) {
				return executeQuery();
			}
			long rows = 0L;
			long digest = 0L;
			for (QueryDigest queryDigest : invokeConcurrently(this::executeQuery)) {
				rows += queryDigest.rowCount;
				digest += queryDigest.digest;
			}
			return new QueryDigest(rows, digest);
		}

		ExecutionEngagement engagement() {
			return engagement;
		}

		private QueryDigest executeQuery() {
			long rows = 0L;
			long digest = 0L;
			try (SailRepositoryConnection connection = repository.getConnection();
					TupleQueryResult result = connection.prepareTupleQuery(QUERY).evaluate()) {
				while (result.hasNext()) {
					BindingSet bindings = result.next();
					long left = literalLong(bindings.getValue("left"), "left");
					long right = literalLong(bindings.getValue("right"), "right");
					digest += rowDigest(left, right);
					rows++;
				}
			}
			return new QueryDigest(rows, digest);
		}

		private ExecutionEngagement captureEngagement(Selector selected, int workersPerQuery) {
			List<String> paths = selected.queryCount == 1
					? List.of(executionPath())
					: invokeConcurrently(this::executionPath);
			ExecutionEngagement observed = new ExecutionEngagement(selected.queryCount, workersPerQuery,
					List.copyOf(paths));
			for (String path : paths) {
				if (selected.parallelEnabled && !path.contains("parallelPipelines")) {
					throw new IllegalStateException(selected + ": expected parallelPipelines but got " + path);
				}
				if (selected.batchEnabled && !path.contains("batch")) {
					throw new IllegalStateException(selected + ": expected batch but got " + path);
				}
				if (!selected.parallelEnabled && path.contains("parallelPipelines")) {
					throw new IllegalStateException(selected + ": unexpectedly used " + path);
				}
				if (!selected.batchEnabled && path.contains("batch")) {
					throw new IllegalStateException(selected + ": unexpectedly used " + path);
				}
			}
			return observed;
		}

		private String executionPath() {
			try (SailRepositoryConnection connection = repository.getConnection()) {
				GenericPlanNode plan = connection.prepareTupleQuery(QUERY)
						.explain(Explanation.Level.Telemetry)
						.toGenericPlanNode();
				String path = findExecutionPath(plan);
				if (path == null) {
					throw new IllegalStateException(selector() + ": telemetry did not report nativeExecutionPath");
				}
				return path;
			}
		}

		private <T> List<T> invokeConcurrently(Callable<T> task) {
			CountDownLatch start = new CountDownLatch(1);
			ArrayList<Future<T>> futures = new ArrayList<>(selector().queryCount);
			try {
				for (int query = 0; query < selector().queryCount; query++) {
					futures.add(queryExecutor.submit(() -> {
						start.await();
						return task.call();
					}));
				}
				start.countDown();
				ArrayList<T> values = new ArrayList<>(futures.size());
				for (Future<T> future : futures) {
					values.add(future.get());
				}
				return values;
			} catch (InterruptedException e) {
				Thread.currentThread().interrupt();
				throw new IllegalStateException("concurrent benchmark query interrupted", e);
			} catch (ExecutionException e) {
				Throwable cause = e.getCause();
				if (cause instanceof RuntimeException runtimeException) {
					throw runtimeException;
				}
				if (cause instanceof Error error) {
					throw error;
				}
				throw new IllegalStateException("concurrent benchmark query failed", cause);
			} finally {
				start.countDown();
			}
		}

		private void verifyDigest(QueryDigest actual) {
			if (!expectedDigest.equals(actual)) {
				throw new IllegalStateException(selector() + ": expected " + expectedDigest + " but got " + actual);
			}
		}

		private void restoreProperties() {
			if (previousProperties == null) {
				return;
			}
			for (Map.Entry<String, String> property : previousProperties.entrySet()) {
				if (property.getValue() == null) {
					System.clearProperty(property.getKey());
				} else {
					System.setProperty(property.getKey(), property.getValue());
				}
			}
		}
