	private static long literalLong(Value value, String bindingName) {
		if (!(value instanceof Literal literal)) {
			throw new IllegalStateException("expected literal ?" + bindingName + " but got " + value);
		}
		return literal.longValue();
	}

	private static String findExecutionPath(GenericPlanNode node) {
		if (node == null) {
			return null;
		}
		String path = node.getStringMetricActual("nativeExecutionPath");
		if (path != null) {
			return path;
		}
		if (node.getPlans() != null) {
			for (GenericPlanNode child : node.getPlans()) {
				String childPath = findExecutionPath(child);
				if (childPath != null) {
					return childPath;
				}
			}
		}
		return null;
	}

	static QueryDigest expectedDigest(int inputRows) {
		long digest = 0L;
		for (int row = 0; row < inputRows; row++) {
			digest += rowDigest(row, rightValue(row));
		}
		return new QueryDigest(inputRows, digest);
	}

	private static long rightValue(int row) {
		return (long) row * 31L + 7L;
	}

	private static long rowDigest(long left, long right) {
		long digest = (DIGEST_OFFSET ^ left) * DIGEST_PRIME;
		return (digest ^ right) * DIGEST_PRIME;
	}

	record QueryDigest(long rowCount, long digest) {
		QueryDigest times(int factor) {
			return new QueryDigest(Math.multiplyExact(rowCount, factor), digest * factor);
		}

		long folded() {
			return digest ^ Long.rotateLeft(rowCount, 17);
		}
	}

	record ExecutionEngagement(int queryCount, int workersPerQuery, List<String> executionPaths) {
	}

	enum Selector {
		SEQUENTIAL(false, false, 1),
		CONCURRENT_TWO(true, false, 2),
		CONCURRENT_FOUR(true, false, 4),
		SERIAL_BATCH(false, true, 1),
		PARALLEL_OVERLAP(true, false, 1);

		private final boolean parallelEnabled;
		private final boolean batchEnabled;
		private final int queryCount;

		Selector(boolean parallelEnabled, boolean batchEnabled, int queryCount) {
			this.parallelEnabled = parallelEnabled;
			this.batchEnabled = batchEnabled;
			this.queryCount = queryCount;
		}
	}
